    fun getRequest(url: String): Response? {
        if (!isSecureUrl(url)) {
            throw IllegalArgumentException("Insecure URL: $url")
        }

        val request = Request.Builder()
            .url(url)
            .build()

        return client.newCall(request).execute()
    }

    private fun isSecureUrl(url: String): Boolean {
        return url.startsWith("https://") || url.startsWith("http://192.168.")
    }
}

